// Gatekeeper: honeypot -> token -> validation -> dedupe -> canonical payload.
// Every rejection returns bot:true; the respond node sends the SAME success
// body either way (no oracle, PRD NFR-Security / acceptance G-3).
// Validation rules mirror widget/src/validate.js verbatim; the S4 validation
// matrix runs the same fixtures against both sides.
// Requires NODE_FUNCTION_ALLOW_BUILTIN=crypto,fs.
const crypto = require('crypto');
const fs = require('fs');
const METRICS = '/home/node/.n8n/wgc-metrics.json';
const body = $json.body || {};
const headers = $json.headers || {};

function bump(field) {
  let m = { days: {} };
  try { m = JSON.parse(fs.readFileSync(METRICS, 'utf8')); } catch (e) { /* first run */ }
  const day = new Date().toISOString().slice(0, 10);
  m.days[day] = m.days[day] || { submissions: 0, bots: 0, delivered_api: 0, delivered_email: 0 };
  m.days[day][field] += 1;
  fs.writeFileSync(METRICS, JSON.stringify(m));
}

function reject(reason) {
  bump('bots');
  return [{ json: { bot: true, reason } }];
}

// 1. Honeypot: field named company must be empty.
if (typeof body.company === 'string' && body.company.trim() !== '') return reject('honeypot');

// 2. Render token: base64(ts.nonce.hmac), age window 2s-2h (server-side
// minimum-fill-time; a direct-post bot cannot hold a valid aged token).
let tokenOk = false;
try {
  const parts = Buffer.from(String(body.token || ''), 'base64').toString('utf8').split('.');
  const ts = parts[0], nonce = parts[1], mac = parts[2] || '';
  const expect = crypto.createHmac('sha256', $env.WGC_HMAC_SECRET).update(ts + '.' + nonce).digest('hex');
  const macBuf = Buffer.from(mac, 'utf8');
  const expBuf = Buffer.from(expect, 'utf8');
  const age = Date.now() - Number(ts);
  tokenOk = macBuf.length === expBuf.length && crypto.timingSafeEqual(macBuf, expBuf) && age >= 2000 && age <= 7200000;
} catch (e) { tokenOk = false; }
if (!tokenOk) return reject('token');

// 3. Validation + normalization (mirror of widget rules).
const errors = [];
function str(v) { return String(v == null ? '' : v).trim(); }
const first_name = str(body.first_name);
if (first_name.length < 1 || first_name.length > 60) errors.push('first_name');
const last_name = str(body.last_name);
if (last_name.length < 1 || last_name.length > 60) errors.push('last_name');
const email = str(body.email);
if (email.length > 254 || !/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) errors.push('email');
const rawPhone = str(body.phone);
const digits = rawPhone.replace(/\D/g, '');
let phone = null;
if (rawPhone.startsWith('+') && !rawPhone.startsWith('+1')) phone = null;
else if (rawPhone.startsWith('+')) phone = digits.length === 11 ? '+' + digits : null;
else if (digits.length === 10) phone = '+1' + digits;
else if (digits.length === 11 && digits[0] === '1') phone = '+' + digits;
if (!phone) errors.push('phone');
const property_address = str(body.property_address);
if (property_address.length < 5 || property_address.length > 120) errors.push('property_address');
let beds = null;
if (str(body.beds) !== '' && body.beds !== null) {
  beds = Number(body.beds);
  if (!Number.isInteger(beds) || beds < 0 || beds > 20) errors.push('beds');
}
let baths = null;
if (str(body.baths) !== '' && body.baths !== null) {
  baths = Number(body.baths);
  if (Number.isNaN(baths) || baths < 0 || baths > 20 || Math.round(baths * 2) !== baths * 2) errors.push('baths');
}
let message = str(body.message);
if (message.length > 1000) errors.push('message');
if (message === '') message = null;
const submission_id = str(body.submission_id);
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{3,4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(submission_id)) errors.push('submission_id');
if (errors.length) return reject('validation:' + errors.join('|'));

// 4. Dedupe: 24h ring buffer in workflow static data (ADR-3: UX, not security).
const sd = $getWorkflowStaticData('global');
const now = Date.now();
sd.seen = (sd.seen || []).filter(function (e) { return now - e.t < 86400000; });
if (sd.seen.some(function (e) { return e.id === submission_id; })) return reject('duplicate');
sd.seen.push({ id: submission_id, t: now });

// 5. Canonical payload v1.0 + server-side consent evidence (FR-3).
const ip = str(headers['x-forwarded-for']).split(',')[0].trim();
const utmIn = body.utm || {};
const payload = {
  schema_version: '1.0',
  submission_id: submission_id,
  first_name: first_name,
  last_name: last_name,
  email: email,
  phone: phone,
  property_address: property_address,
  beds: beds,
  baths: baths,
  message: message,
  source: str(body.source) || 'Website - wgcassetguide',
  page_url: str(body.page_url).slice(0, 500),
  utm: {
    source: str(utmIn.source).slice(0, 100),
    medium: str(utmIn.medium).slice(0, 100),
    campaign: str(utmIn.campaign).slice(0, 100)
  },
  consent: {
    tcpa: body.consent && body.consent.tcpa === true,
    timestamp: body.consent && str(body.consent.timestamp) ? str(body.consent.timestamp) : new Date().toISOString(),
    text_version: (body.consent && str(body.consent.text_version)) || 'WGC-TCPA-2026-07-v1',
    ip: ip,
    user_agent: str(headers['user-agent']).slice(0, 400)
  }
};
bump('submissions');
return [{ json: { bot: false, payload: payload } }];
